// Pull data from your existing nodes
const requests  = $items('requests1').map(i => i.json);
const approvals = $items('approvals1').map(i => i.json);
const users     = $items('users').map(i => i.json);

// Index users by id for quick lookup
const usersById = Object.fromEntries(users.map(u => [u.id, u]));

// Group approvals by request_id and embed approver info
const approvalsByRequest = {};
for (const a of approvals) {
  const approver = usersById[a.approver_user_id] || null;
  const enriched = { ...a, approver };
  (approvalsByRequest[a.request_id] ||= []).push(enriched);
}

// Emit one item per request with approvals[]
return requests.map(r => ({
  json: {
    ...r,
    approvals: approvalsByRequest[r.id] || []
  }
}));

