</head>
<body>
  <header>
    <h1>Согласования по заявкам</h1>
    <div class="panel"></div>
  </header>

  <main>
    <div class="table-card">
      <table id="tbl">
        <thead>
          <tr>
            <th class="sortable" data-key="id">ID заявки <span class="sort"></span></th>
            <th class="sortable" data-key="vendor">Поставщик <span class="sort"></span></th>
            <th class="sortable" data-key="amount">Сумма <span class="sort"></span></th>
            <th class="sortable" data-key="submitted_at">Создана <span class="sort"></span></th>

            <th class="sortable" data-key="category">Категория <span class="sort"></span></th>
            <th class="sortable" data-key="payment_type">Тип оплаты <span class="sort"></span></th>
            <th class="sortable" data-key="payment_purpose">Назначение платежа <span class="sort"></span></th>
            <th class="sortable" data-key="urgency">Срочность <span class="sort"></span></th>
            <th class="sortable" data-key="requester">Инициатор <span class="sort"></span></th>
            <!-- УДАЛЕНО company_payer, title -->
            <th class="sortable" data-key="description">Описание <span class="sort"></span></th>

            <th>Шаги</th>
            <th class="sortable" data-key="status">Статус <span class="sort"></span></th>
            <th class="sortable" data-key="current_step">Текущий шаг <span class="sort"></span></th>
            <th class="sortable" data-key="last_decision_at">Последнее решение <span class="sort"></span></th>
            <th class="sortable" data-key="messages">Сообщения <span class="sort"></span></th>
            <th></th>
          </tr>
        </thead>
        <tbody id="tbody">
          <tr><td colspan="16" class="muted">Отрисовка…</td></tr>
        </tbody>
      </table>
    </div>
  </main>

  <dialog id="modal">
    <div class="modal-head">
      <div><strong>Заявка <span id="m-id"></span></strong></div>
      <button class="close" onclick="modal.close()">Закрыть</button>
    </div>
    <div class="modal-body">
      <div class="table-card" style="background:#0f1218">
        <table>
          <thead>
            <tr>
              <th>№</th>
              <th>ID соглас.</th>
              <th>ID заявки</th>
              <th>Шаг</th>
              <th>Тип шага</th>
              <th>Согласующий (имя)</th>
              <th>Approver user ID</th>
              <th>Роль</th>
              <th>TG чат (из approval)</th>
              <th>TG чат (из профиля)</th>
              <th>Manager ID</th>
              <th>OOO до</th>
              <th>Статус</th>
              <th>Дата решения</th>
              <th>Комментарий</th>
              <th>Сообщение отправлено</th>
              <th>ID сообщения</th>
            </tr>
          </thead>
          <tbody id="m-approvals"></tbody>
        </table>
      </div>
    </div>
  </dialog>

  <script>window.SERVER_DATA = ${JSON.stringify(data)};</script>

  <script>
  const $ = (s)=>document.querySelector(s);
  const tbody = document.getElementById('tbody');
  const modal = document.getElementById('modal');
  let approvalsData = Array.isArray(window.SERVER_DATA) ? window.SERVER_DATA : [];
  let sortKey = 'id';
  let sortDir = 'asc';

  const esc = (v='') => String(v)
    .replace(/&/g,'&amp;').replace(/</g,'&lt;')
    .replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');

  const truncate = (s, n=160) => {
    const str = String(s||'');
    return str.length > n ? str.slice(0, n-1) + '…' : str;
  };

  const fmtDate = (d)=> d ? new Date(d).toLocaleString('ru-RU', {
    hour:'2-digit', minute:'2-digit', day:'2-digit', month:'2-digit', year:'numeric'
  }) : '';

  const fmtMoney = (v, cur='UZS') => {
    const n = Number(v);
    return Number.isFinite(n)
      ? new Intl.NumberFormat('ru-RU', { style:'currency', currency: cur }).format(n)
      : '';
  };

  function statusLabel(s){
    switch (s) {
      case 'PAYED': return 'ОПЛАЧЕНО';
      case 'APPROVED': return 'ОДОБРЕНО';
      case 'REJECTED': return 'ОТКЛОНЕНО';
      case 'UNDER_REVIEW': return 'НА РАССМОТРЕНИИ';
      default: return String(s || '');
    }
  }
  function decisionLabel(d){
    const x = (d || 'pending').toLowerCase();
    if (x === 'approved') return 'одобрено';
    if (x === 'rejected') return 'отклонено';
    return 'в ожидании';
  }

  // срочность → чип
  function badgeUrgency(u){
    const val = String(u||'').trim();
    if (val === 'Срочно') return '<span class="urgency urgent">Срочно</span>';
    if (val === 'Обычно') return '<span class="urgency normal">Обычно</span>';
    return esc(val);
  }

  function stepAggregate(items){
    const decisions = items.map(x=>x.decision);
    if(decisions.includes('rejected')) return 'rejected';
    if(items.length>0 && decisions.every(d=>d==='approved')) return 'approved';
    return 'pending';
  }
  function deriveStatus(items){
    if(items.some(x=>x.decision==='rejected')) return 'REJECTED';
    if(items.length>0 && items.every(x=>x.decision==='approved')) return 'APPROVED';
    return 'UNDER_REVIEW';
  }
  function currentStep(items){
    const byStep = new Map();
    for(const it of items){ if(!byStep.has(it.step)) byStep.set(it.step, []); byStep.get(it.step).push(it); }
    const steps = [...byStep.keys()].sort((a,b)=>a-b);
    for(const s of steps){ if(stepAggregate(byStep.get(s)) !== 'approved') return s; }
    return steps[steps.length-1] || 1;
  }
  function lastDecisionAt(items){
    const dates = items.map(x=> x.decided_at).filter(Boolean).sort();
    return dates.length ? dates[dates.length-1] : '';
  }
  function stepsCompact(items){
    const byStep = new Map();
    for(const it of items){ if(!byStep.has(it.step)) byStep.set(it.step, []); byStep.get(it.step).push(it); }
    const steps = [...byStep.keys()].sort((a,b)=>a-b);
    const icon = (agg)=> agg==='approved' ? '✅' : (agg==='rejected' ? '❌' : '⏳');
    return steps.map(s=> s + icon(stepAggregate(byStep.get(s)))).join(' ');
  }
  function messagesSummary(items){
    const sent = items.filter(x=>x.message_sent).length;
    return sent + '/' + items.length;
  }

  function badge(status){ return '<span class="status ' + status + '">' + statusLabel(status) + '</span>'; }
  function badgeDecision(dec){
    const cls = (dec||'pending').toLowerCase();
    return '<span class="status ' + cls + '">' + decisionLabel(dec) + '</span>';
  }

  function compare(a,b){
    const dir = sortDir==='asc' ? 1 : -1;
    const v1 = a[sortKey], v2 = b[sortKey];

    if(sortKey==='status'){
      const order = {UNDER_REVIEW:0, APPROVED:1, REJECTED:2, PAYED:3};
      return ((order[v1]??9) - (order[v2]??9)) * dir;
    }
    if(sortKey==='submitted_at' || sortKey==='last_decision_at'){
      return ((v1?new Date(v1).getTime():0) - (v2?new Date(v2).getTime():0)) * dir;
    }
    if(sortKey==='amount'){
      return ((+v1 || 0) - (+v2 || 0)) * dir;
    }
    if(sortKey==='current_step' || sortKey==='id' || sortKey==='messages'){
      return ((+v1||0) - (+v2||0)) * dir;
    }
    if(typeof v1 === 'string' && typeof v2 === 'string'){
      return v1.localeCompare(v2,'ru') * dir;
    }
    return ((v1??0) - (v2??0)) * dir;
  }

  function setSortIndicators(){
    document.querySelectorAll('thead th.sortable').forEach(th=>{
      const span = th.querySelector('.sort');
      if(!span) return;
      const key = th.dataset.key;
      span.textContent = (key===sortKey) ? (sortDir==='asc'?'▲':'▼') : '';
    });
  }

  function renderList(requests){
    if(!Array.isArray(requests)){
      tbody.innerHTML = '<tr><td colspan="16" class="muted">Неожиданный ответ</td></tr>';
      return;
    }
    if(!requests.length){
      tbody.innerHTML = '<tr><td colspan="16" class="muted">Нет данных</td></tr>';
      return;
    }
    const rows = requests.map(req=>{
      const approvals = Array.isArray(req.approvals)? req.approvals : [];
      const status = req.status && ['PAYED','APPROVED','REJECTED','UNDER_REVIEW'].includes(req.status)
        ? req.status : deriveStatus(approvals);
      return {
        id: req.id,
        vendor: esc(req.vendor || ''),
        amount: Number(req.amount ?? req.total ?? req.sum ?? 0),
        currency: req.currency || 'UZS',
        submitted_at: req.submitted_at || '',

        category: esc(req.category || ''),
        payment_type: esc(req.payment_type || ''),
        payment_purpose: esc(req.payment_purpose || ''),
        urgency: esc(req.urgency || ''),
        requester: esc(req.requester || ''),
        // удалены company_payer и title
        description: esc(truncate(req.description || '', 200)),

        steps: stepsCompact(approvals),
        status,
        current_step: approvals.length ? currentStep(approvals) : '',
        last_decision_at: lastDecisionAt(approvals) || '',
        messages: messagesSummary(approvals),
        _approvals: approvals
      };
    });

    rows.sort(compare);

    tbody.innerHTML = rows.map(r=>(
      '<tr>'
        + '<td class="nowrap">#' + r.id + '</td>'
        + '<td>' + r.vendor + '</td>'
        + '<td class="nowrap">' + fmtMoney(r.amount, r.currency) + '</td>'
        + '<td class="nowrap">' + fmtDate(r.submitted_at) + '</td>'

        + '<td>' + r.category + '</td>'
        + '<td>' + r.payment_type + '</td>'
        + '<td>' + r.payment_purpose + '</td>'
        + '<td>' + badgeUrgency(r.urgency) + '</td>'
        + '<td>' + r.requester + '</td>'
        + '<td>' + r.description + '</td>'

        + '<td>' + r.steps + '</td>'
        + '<td>' + badge(r.status) + '</td>'
        + '<td>' + r.current_step + '</td>'
        + '<td class="nowrap">' + fmtDate(r.last_decision_at) + '</td>'
        + '<td>' + r.messages + '</td>'
        + '<td><span class="link" data-id="' + r.id + '">Открыть</span></td>'
      + '</tr>'
    )).join('');

    tbody.querySelectorAll('.link').forEach(a=> a.addEventListener('click', ()=> openDetail(Number(a.dataset.id))));
    setSortIndicators();
  }

  function openDetail(requestId){
    const req = approvalsData.find(x=> x.id === requestId);
    if(!req) return;
    document.getElementById('m-id').textContent = '#' + requestId;
    const approvals = (req.approvals||[]).slice().sort((a,b)=> (a.step||0)-(b.step||0) || (a.id||0)-(b.id||0));
    const rowsHtml = approvals.map((x,i)=> (
      '<tr>'
        + '<td>' + (i+1) + '</td>'
        + '<td>' + (x.id ?? '') + '</td>'
        + '<td>' + (x.request_id ?? '') + '</td>'
        + '<td>' + (x.step ?? '') + '</td>'
        + '<td>' + esc(x.step_type || '') + '</td>'
        + '<td>' + esc(x.approver?.name || '') + '</td>'
        + '<td>' + (x.approver_user_id ?? '') + '</td>'
        + '<td>' + esc(x.approver?.role ?? '') + '</td>'
        + '<td>' + (x.approver_tg_id ?? '') + '</td>'
        + '<td>' + esc(x.approver?.telegram_chat_id ?? '') + '</td>'
        + '<td>' + (x.approver?.manager_id ?? '') + '</td>'
        + '<td class="nowrap">' + fmtDate(x.approver?.ooo_until) + '</td>'
        + '<td>' + badgeDecision(x.decision) + '</td>'
        + '<td class="nowrap">' + fmtDate(x.decided_at) + '</td>'
        + '<td>' + esc(x.comment || '') + '</td>'
        + '<td>' + (x.message_sent ? '✓' : '—') + '</td>'
        + '<td>' + (x.message_id ?? '') + '</td>'
      + '</tr>'
    )).join('');
    document.getElementById('m-approvals').innerHTML = rowsHtml || '<tr><td colspan="17" class="muted">Нет данных</td></tr>';
    modal.showModal();
  }

  document.addEventListener('DOMContentLoaded', ()=>{
    document.querySelectorAll('thead th.sortable').forEach(th=>{
      th.addEventListener('click', ()=>{
        const key = th.dataset.key;
        if(!key) return;
        if(sortKey === key) sortDir = (sortDir==='asc') ? 'desc' : 'asc';
        else { sortKey = key; sortDir = 'asc'; }
        renderList(approvalsData);
      });
    });

    renderList(approvalsData);
  });
  </script>
</body>
</html>`;
})()
}}
